import heapq
from collections import deque

class MKAverage:

    def __init__(self, m: int, k: int):
        self.m = m
        self.k = k
        self.stream = deque()
        self.small = []
        self.large = []

    def addElement(self, num: int) -> None:
        self.stream.append(num)
        if len(self.stream) > self.m:
            self.stream.popleft()
        if len(self.stream) == self.m:
            heapq.heappush(self.small, -self.stream[0])
            heapq.heappush(self.large, -heapq.heappop(self.small))
            while len(self.small) > self.k:
                heapq.heappush(self.large, -heapq.heappop(self.small))
            while len(self.large) > self.m - self.k - self.k:
                heapq.heappush(self.small, -heapq.heappop(self.large))

    def calculateMKAverage(self) -> int:
        if len(self.stream) < self.m:
            return -1
        total = 0
        for _ in range(self.m - self.k * 2):
            if self.small and -self.small[0] < self.large[0]:
                total += -heapq.heappop(self.small)
            else:
                total += heapq.heappop(self.large)
        while self.small:
            heapq.heappush(self.stream, -heapq.heappop(self.small))
        while self.large:
            heapq.heappush(self.stream, heapq.heappop(self.large))
        return total // (self.m - self.k * 2)


